noncompliant:
// Noncompliant - no format provider specified
var date1 = DateTime.Parse(dateString);

// Noncompliant - null format provider
var date2 = DateTime.ParseExact(dateString, "yyyy-MM-dd", null);

// Noncompliant - TryParse without format provider
DateTime.TryParse(dateString, out var date3);

compliant:
// Compliant - using CultureInfo.InvariantCulture
var date1 = DateTime.Parse(dateString, CultureInfo.InvariantCulture);

// Compliant - format provider specified
var date2 = DateTime.ParseExact(dateString, "yyyy-MM-dd", CultureInfo.InvariantCulture);

// Compliant - TryParse with format provider
DateTime.TryParse(dateString, CultureInfo.InvariantCulture, DateTimeStyles.None, out var date3);
